def get_weather(location: str, unit: str = "celsius") -> dict:
    """Mock weather function."""
    return {"location": location, "temperature": 22, "unit": unit}

# Define function for Gemini
weather_tool = genai.protos.Tool(
    function_declarations=[
        genai.protos.FunctionDeclaration(
            name="get_weather",
            description="Get current weather for a location",
            parameters=genai.protos.Schema(
                type=genai.protos.Type.OBJECT,
                properties={
                    "location": genai.protos.Schema(
                        type=genai.protos.Type.STRING,
                        description="City name"
                    ),
                    "unit": genai.protos.Schema(
                        type=genai.protos.Type.STRING,
                        enum=["celsius", "fahrenheit"]
                    )
                },
                required=["location"]
            )
        )
    ]
)

def chat_with_functions(user_message: str):
    """Gemini with function calling."""
    model = genai.GenerativeModel(
        "gemini-1.5-pro",
        tools=[weather_tool]
    )

    chat = model.start_chat()
    response = chat.send_message(user_message)

    # Check for function calls
    for part in response.parts:
        if hasattr(part, "function_call"):
            fn = part.function_call

            # Execute function
            if fn.name == "get_weather":
                result = get_weather(**dict(fn.args))

                # Send result back
                response = chat.send_message(
                    genai.protos.Content(
                        parts=[genai.protos.Part(
                            function_response=genai.protos.FunctionResponse(
                                name=fn.name,
                                response={"result": result}
                            )
                        )]
                    )
                )

    return response.text

from google.generativeai.types import HarmCategory, HarmBlockThreshold

def create_safe_model():
    """Model with custom safety settings."""
    model = genai.GenerativeModel(
        "gemini-1.5-pro",
        safety_settings={
            HarmCategory.HARM_CATEGORY_HARASSMENT: HarmBlockThreshold.BLOCK_MEDIUM_AND_ABOVE,
            HarmCategory.HARM_CATEGORY_HATE_SPEECH: HarmBlockThreshold.BLOCK_MEDIUM_AND_ABOVE,
            HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT: HarmBlockThreshold.BLOCK_MEDIUM_AND_ABOVE,
            HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT: HarmBlockThreshold.BLOCK_MEDIUM_AND_ABOVE,
        }
    )
    return model

from dataclasses import dataclass
from typing import Optional, List, Any
import logging

@dataclass
class GeminiConfig:
    model: str = "gemini-1.5-pro"
    temperature: float = 0.7
    top_p: float = 0.95
    top_k: int = 40
    max_output_tokens: int = 8192

class GeminiService:
    """Production-ready Gemini service."""

    def __init__(self, api_key: Optional[str] = None):
        genai.configure(api_key=api_key or os.environ.get("GOOGLE_API_KEY"))
        self.logger = logging.getLogger(__name__)

    def complete(
        self,
        prompt: str,
        config: Optional[GeminiConfig] = None
    ) -> dict:
        """Execute completion."""
        config = config or GeminiConfig()

        model = genai.GenerativeModel(config.model)

        generation_config = genai.GenerationConfig(
            temperature=config.temperature,
            top_p=config.top_p,
            top_k=config.top_k,
            max_output_tokens=config.max_output_tokens
        )

        try:
            response = model.generate_content(
                prompt,
                generation_config=generation_config
            )

            return {
                "content": response.text,
                "usage": {
                    "prompt_tokens": response.usage_metadata.prompt_token_count,
                    "output_tokens": response.usage_metadata.candidates_token_count
                },
                "finish_reason": response.candidates[0].finish_reason.name
            }
        except Exception as e:
            self.logger.error(f"Gemini API error: {e}")
            raise
